-- Criar tabelas curso e serie
CREATE TABLE curso (
    id BIGSERIAL PRIMARY KEY,
    nome VARCHAR(255) NOT NULL,
    descricao TEXT
);

CREATE TABLE serie (
    id BIGSERIAL PRIMARY KEY,
    curso_id BIGINT NOT NULL REFERENCES curso(id) ON DELETE CASCADE,
    nome VARCHAR(255) NOT NULL
);

-- Modificar modulo
ALTER TABLE modulo DROP CONSTRAINT IF EXISTS modulo_nome_key;
ALTER TABLE modulo ADD COLUMN serie_id BIGINT REFERENCES serie(id) ON DELETE CASCADE;

-- Modificar aula
ALTER TABLE aula ADD COLUMN objetivo VARCHAR(512);
ALTER TABLE aula ADD COLUMN recursos_necessarios VARCHAR(512);
ALTER TABLE aula ADD COLUMN duracao_sugerida VARCHAR(100);

