INSERT INTO curso (id, nome, descricao) VALUES
(1, 'Educação Digital', 'Desenvolver competências relacionadas ao uso consciente, crítico, seguro e produtivo das tecnologias digitais, seguindo as orientações da BNCC para o Ensino Médio.');
INSERT INTO serie (id, curso_id, nome) VALUES
(1, 1, '1º Ano'),
(2, 1, '2º Ano'),
(3, 1, '3º Ano');
INSERT INTO modulo (id, serie_id, nome, descricao) VALUES
(1, 1, 'Introdução à Computação', 'Fundamentos conceituais, histórico e áreas da computação.'),
(2, 1, 'Conhecendo o Computador', 'Componentes de hardware, software, periféricos e preservação ambiental.'),
(3, 1, 'Internet', 'Funcionamento técnico da internet, serviços digitais e inclusão social.'),
(4, 1, 'Segurança Digital', 'Estratégias de proteção pessoal, combate a golpes e fake news.'),
(5, 1, 'Cidadania Digital', 'Ética na rede, saúde mental, cyberbullying e direitos autorais.'),
(6, 1, 'Projeto Final', 'Aplicação prática dos conceitos fundamentais de cidadania digital e investigação.');
INSERT INTO modulo (id, serie_id, nome, descricao) VALUES
(7, 2, 'Hardware na Prática', 'Arquitetura física detalhada de computadores e smartphones.'),
(8, 2, 'Sistemas Operacionais e Softwares', 'Gerenciamento de softwares, interfaces de usuários e extensões de arquivos.'),
(9, 2, 'Pensamento Computacional', 'Os quatro pilares da lógica computacional e fluxogramas.'),
(10, 2, 'Tecnologia para Estudo e Trabalho', 'Uso produtivo e colaborativo de processadores de textos, planilhas e slides.'),
(11, 2, 'Produção Digital', 'Criação e edição básica de mídias de vídeo, áudio, podcasts e imagens.'),
(12, 2, 'Projeto Final', 'Resolução de problemas do cotidiano escolar aplicando lógica computacional.');
INSERT INTO modulo (id, serie_id, nome, descricao) VALUES
(13, 3, 'Inteligência Artificial', 'Histórico, Machine Learning, IA Generativa e dilemas éticos da automação.'),
(14, 3, 'Desenvolvimento de Soluções Digitais', 'Ciclo de vida de software, conceitos básicos de web e plataformas no-code.'),
(15, 3, 'Segurança da Informação', 'Leis de proteção de dados (LGPD), engenharia social, malwares e backup.'),
(16, 3, 'Tecnologia e Sociedade', 'Efeitos socioculturais da automação, deepfakes, sustentabilidade e dependência digital.'),
(17, 3, 'Profissões em Tecnologia', 'Mapeamento de carreiras em TI, formação acadêmica e mercado de trabalho.'),
(18, 3, 'Projeto Final', 'Modelagem, ética e prototipagem de uma solução digital para impacto social.');
INSERT INTO aula (id, modulo_id, titulo, descricao, ordem, objetivo, recursos_necessarios, duracao_sugerida) VALUES
(101, 1, 'O que é Computação?', 'Apresentação dos conceitos básicos sobre computação e dados. Os alunos entenderão que computar significa calcular e processar, indo muito além de apenas acessar redes sociais ou navegar no celular.', 1, 'Compreender a diferença entre usar aparelhos digitais e a ciência da Computação, reconhecendo a computação como o processamento sistemático de informações.', 'Projetor ou TV, quadro escolar, caderno e caneta.', '50 minutos'),
(102, 1, 'A História da Computação: Da Contagem aos Supercomputadores', 'Um passeio histórico que vai do ábaco e das máquinas mecânicas de calcular ao surgimento dos primeiros computadores eletrônicos (como o ENIAC) e a popularização dos computadores pessoais.', 2, 'Reconhecer a evolução histórica das ferramentas de cálculo e processamento até a criação dos computadores modernos.', 'Projetor ou TV para exibição de imagens históricas, quadro escolar.', '50 minutos'),
(103, 1, 'Onde a Computação Está Presente?', 'Análise do cotidiano para descobrir microcomputadores em eletrodomésticos, carros, semáforos e caixas eletrônicos, mostrando que a computação não está apenas em notebooks e celulares.', 3, 'Identificar sistemas computacionais embarcados em aparelhos de uso diário, percebendo a presença invisível da computação.', 'Quadro escolar, folhas de papel para atividade de mapeamento em grupo.', '50 minutos'),
(104, 1, 'As Grandes Áreas da Computação', 'Uma introdução descomplicada sobre o que estuda cada área: hardware (físico), software (lógica/programas), redes (conexões), inteligência artificial (aprendizado de máquina) e segurança.', 4, 'Conhecer as subdivisões da ciência da computação e o escopo de atuação de cada uma.', 'Projetor ou TV, quadro escolar.', '50 minutos'),
(105, 1, 'Como os Computadores "Pensam"? Introdução ao Binário', 'Uma aula prática e desplugada que usa lâmpadas desenhadas ou cartões de papel para demonstrar o sistema binário (0 e 1) de maneira visual e interativa.', 5, 'Compreender o conceito de código binário e como os computadores representam números e letras usando apenas dois estados (ligado/desligado).', 'Cartões de papel numerados (representando potências de 2) para atividade desplugada, quadro escolar.', '50 minutos'),
(106, 1, 'Mulheres e Pioneiros da Computação', 'Apresentação de figuras essenciais como Ada Lovelace (primeira programadora), Grace Hopper (criadora de linguagens de programação), Margaret Hamilton (software da missão Apollo) e cientistas nacionais.', 6, 'Valorizar a contribuição histórica de mulheres e cientistas pioneiros no desenvolvimento da computação.', 'Projetor ou TV para apresentação de fotos/biografias.', '50 minutos'),
(107, 1, 'Mitos e Curiosidades do Mundo Digital', 'Debate divertido sobre mitos do cotidiano, como se colocar um imã perto da tela estraga o PC, se o celular grava tudo o que falamos e de onde surgiu o termo "bug".', 7, 'Desmistificar crenças populares sobre tecnologia e computadores, estimulando a curiosidade intelectual.', 'Projetor ou TV, quadro escolar.', '50 minutos');
INSERT INTO aula (id, modulo_id, titulo, descricao, ordem, objetivo, recursos_necessarios, duracao_sugerida) VALUES
(108, 2, 'O Corpo e a Mente: Hardware vs. Software', 'Utilizando analogias simples, os alunos entenderão a diferença conceitual e a interdependência entre a parte física e os programas de computadores e smartphones.', 1, 'Distinguir os componentes físicos (hardware) das instruções lógicas (software) de um computador.', 'Projetor ou TV, quadro escolar.', '50 minutos'),
(109, 2, 'Os Sentidos do Computador: Dispositivos de Entrada', 'Estudo sobre teclados, mouses, microfones, câmeras e sensores de movimento. A aula também explora a importância desses dispositivos em tecnologias de acessibilidade.', 2, 'Identificar os dispositivos utilizados para enviar dados ao computador, compreendendo seu papel na interação humano-computador.', 'Dispositivos reais antigos (opcional, para manusear), quadro escolar.', '50 minutos'),
(110, 2, 'A Voz do Computador: Dispositivos de Saída', 'Análise de monitores, impressoras, fones de ouvido e caixas de som, discutindo como a informação digital é convertida em sinais visuais, sonoros ou táteis.', 3, 'Identificar os periféricos que exibem ou emitem as informações processadas pelo computador para o usuário.', 'Projetor ou TV, quadro escolar.', '50 minutos'),
(111, 2, 'Onde Guardamos as Informações? Armazenamento Físico', 'Explicação prática sobre como a informação é guardada de forma temporária enquanto o aparelho está ligado e de forma permanente para não se perder quando ele é desligado.', 4, 'Diferenciar a memória de trabalho (RAM) dos dispositivos de armazenamento permanente (HD, SSD e Pendrive).', 'Peças antigas de HD e pendrives (opcional), projetor ou TV, quadro.', '50 minutos'),
(112, 2, 'Como o Hardware e o Software Conversam?', 'Apresentação visual da jornada de um clique no mouse até a alteração na tela, demonstrando como o processador e o sistema operacional coordenam essa conversa.', 5, 'Compreender o ciclo básico de entrada, processamento, armazenamento e saída de dados.', 'Projetor ou TV, folhas de papel para desenho do fluxo.', '50 minutos'),
(113, 2, 'Cuidando do Equipamento: Higiene e Conservação', 'Orientações preventivas para evitar que poeira, umidade, quedas e superaquecimento estraguem os aparelhos, promovendo a longevidade dos dispositivos dos próprios alunos.', 6, 'Aprender práticas corretas de limpeza, ventilação e conservação física de computadores e celulares.', 'Quadro escolar, folheto digital ou físico com dicas de cuidados.', '50 minutos'),
(114, 2, 'O Ciclo de Vida da Máquina e a Obsolescência Programada', 'Discussão crítica sobre o descarte de celulares antigos, o consumismo tecnológico e o que é o lixo eletrônico, incentivando práticas sustentáveis.', 7, 'Refletir sobre a obsolescência programada de aparelhos eletrônicos e seus impactos no meio ambiente.', 'Projetor ou TV, notícias impressas ou projetadas sobre lixo eletrônico.', '50 minutos');
INSERT INTO aula (id, modulo_id, titulo, descricao, ordem, objetivo, recursos_necessarios, duracao_sugerida) VALUES
(115, 3, 'A Grande Teia: O que é a Internet e Como Ela Surgiu?', 'Desmistificação da internet mostrando que ela não está "no ar", mas sim conectada por cabos gigantescos no fundo do mar. Contexto da Guerra Fria e a criação das primeiras redes.', 1, 'Compreender a internet como uma rede física global de computadores interconectados e conhecer sua origem histórica.', 'Projetor ou TV para mapa dos cabos submarinos mundiais, quadro escolar.', '50 minutos'),
(116, 3, 'Como a Informação Viaja pela Internet?', 'Uma dinâmica teatral onde os alunos enviam "cartas divididas" uns aos outros pela sala de aula para entender como os pacotes de dados viajam e se reagrupam no destino final.', 2, 'Entender o conceito de roteamento, pacotes de dados e endereços IP de forma simples.', 'Cartões ou pedaços de papel (para simular pacotes), envelopes e caneta.', '50 minutos'),
(117, 3, 'Portas de Entrada: Navegadores e URLs', 'Explicação de como o navegador traduz código em páginas bonitas. Análise das partes de um endereço da web (HTTP/HTTPS, domínio, caminhos) para identificar páginas confiáveis.', 3, 'Compreender a função dos navegadores de internet e a estrutura básica de um link (URL).', 'Projetor ou TV, quadro escolar.', '50 minutos'),
(118, 3, 'Como Encontrar Qualquer Coisa: Motores de Busca', 'Apresentação de truques úteis de pesquisa (uso de aspas, exclusão de termos com hífen, busca por formato de arquivo) para tornar as pesquisas escolares muito mais rápidas e eficientes.', 4, 'Aplicar técnicas avançadas de pesquisa na web e entender como os buscadores catalogam o conhecimento.', 'Projetor ou TV, celulares dos alunos (se permitido) ou exemplos no quadro.', '50 minutos'),
(119, 3, 'Onde Fica a Nuvem?', 'Esclarecimento de que a "nuvem" é um conjunto de computadores distantes (servidores/data centers) que guardam e processam nossos arquivos, permitindo acessá-los de qualquer dispositivo.', 5, 'Explicar o conceito de computação em nuvem e suas vantagens no compartilhamento e armazenamento de arquivos.', 'Projetor ou TV, quadro escolar.', '50 minutos'),
(120, 3, 'Serviços Digitais do Cotidiano', 'Tour por ferramentas de e-mail, mapas e GPS, streaming de áudio/vídeo, serviços públicos digitais de emissão de documentos (Gov.br) e carteiras digitais.', 6, 'Conhecer as diferentes categorias de serviços web úteis para a vida civil, acadêmica e profissional.', 'Projetor ou TV, quadro.', '50 minutos'),
(121, 3, 'Inclusão Digital e o Direito à Conexão', 'Discussão sobre as diferenças de acesso (velocidade, franquia de dados e qualidade de tela) e como a falta de internet afeta os estudos e as chances de emprego dos cidadãos.', 7, 'Refletir criticamente sobre as barreiras socioeconômicas de acesso à internet de qualidade no Brasil.', 'Dados e infográficos sobre exclusão digital no Brasil (projetados ou impressos).', '50 minutos');
INSERT INTO aula (id, modulo_id, titulo, descricao, ordem, objetivo, recursos_necessarios, duracao_sugerida) VALUES
(122, 4, 'Chaves Digitais: A Importância de Senhas Fortes', 'Dinâmica prática demonstrando por que senhas óbvias são descobertas facilmente por computadores e como construir senhas fáceis de lembrar, mas difíceis de hackear.', 1, 'Criar e gerenciar senhas pessoais seguras e compreender a importância da verificação em duas etapas.', 'Quadro escolar, papel e caneta para simulação de criação de senhas.', '50 minutos'),
(123, 4, 'Cuidado com a Isca! O que é Phishing?', 'Análise visual de mensagens reais de golpistas que fingem ser bancos, correios ou promoções imperdíveis. O estudante aprenderá a buscar pistas de fraude antes de clicar.', 2, 'Identificar e-mails, SMS e links fraudulentos projetados para roubar informações pessoais.', 'Projetor ou TV com prints de e-mails/mensagens suspeitas.', '50 minutos'),
(124, 4, 'Golpes Virtuais do Dia a Dia', 'Análise de golpes recorrentes, como a clonagem ou roubo de contas do WhatsApp, falsos sorteios no Instagram, perfis fakes de lojas e o golpe do PIX agendado.', 3, 'Reconhecer fraudes virtuais comuns que ocorrem em aplicativos de mensagens e redes sociais.', 'Projetor ou TV, quadro escolar.', '50 minutos'),
(125, 4, 'Desinformação na Rede: Combatendo Fake News', 'Como as Fake News são escritas para despertar emoções fortes. Passos simples para verificar notícias antes de repassar (analisar a fonte, checar data, pesquisar em agências de checagem).', 4, 'Desenvolver uma postura analítica e crítica para identificar boatos e notícias falsas compartilhados nas redes.', 'Exemplos de boatos históricos da internet impressos ou projetados.', '50 minutos'),
(126, 4, 'Quem Está Te Vendo? Privacidade e Redes Sociais', 'Análise do valor comercial das informações privadas e das configurações de privacidade de aplicativos famosos, promovendo a reflexão antes de publicar fotos e locais em tempo real.', 5, 'Configurar restrições de privacidade e compreender os riscos de expor dados pessoais excessivamente.', 'Projetor ou TV para exibição das telas de configuração de privacidade de apps conhecidos.', '50 minutos'),
(127, 4, 'Segurança em Celulares e Wi-Fi Público', 'Explicação dos riscos ao conectar-se a redes de Wi-Fi gratuitas e a importância de analisar as permissões de acesso (câmera, microfone, contatos) solicitadas por aplicativos.', 6, 'Aprender a proteger smartphones contra conexões sem fio perigosas e gerenciar permissões de apps.', 'Quadro escolar, celular pessoal do professor ou alunos (opcional).', '50 minutos'),
(128, 4, 'Criando um Escudo Digital Familiar', 'Os alunos trabalharão em grupos criando panfletos físicos ou cartazes ilustrativos com dicas simples de segurança para levar para casa e instruir pais ou avós.', 7, 'Sintetizar as práticas aprendidas de segurança digital e transmiti-las para a comunidade familiar.', 'Papel cartolina, canetas coloridas, tesoura e cola.', '50 minutos');
INSERT INTO aula (id, modulo_id, titulo, descricao, ordem, objetivo, recursos_necessarios, duracao_sugerida) VALUES
(129, 5, 'Viver Conectado: O Impacto das Redes Sociais', 'Reflexão sobre como as plataformas são feitas para nos prender a atenção e como os feeds criam "bolhas de opinião", onde apenas vemos ideias parecidas com as nossas.', 1, 'Analisar a dinâmica de funcionamento das redes sociais, bolhas de informação e os algoritmos de engajamento.', 'Projetor ou TV, quadro escolar.', '50 minutos'),
(130, 5, 'Violência Oculta: Entendendo o Cyberbullying', 'Discussão sobre as consequências emocionais das agressões online, a falsa sensação de anonimato na rede e o papel do espectador que compartilha piadas ofensivas.', 2, 'Identificar situações de assédio, agressão e zombaria na internet, sabendo como denunciar e acolher as vítimas.', 'Cartazes com histórias hipotéticas para reflexão em grupo.', '50 minutos'),
(131, 5, 'O Dono da Obra: Direitos Autorais e Internet', 'Explicação do que é plágio, pirataria e a importância de dar os créditos em trabalhos escolares. Introdução a conteúdos livres via licenças Creative Commons.', 3, 'Compreender as regras de direitos autorais de materiais da internet e como usar fontes de imagens e textos corretamente.', 'Quadro escolar, exemplos práticos de licenças de uso.', '50 minutos'),
(132, 5, 'Ética Digital e Netiqueta', 'Práticas de convivência na rede, uso correto de letras maiúsculas (que representam grito), respeito às opiniões contrárias e formas saudáveis de argumentar sem ofender.', 4, 'Desenvolver hábitos de escrita respeitosos e construtivos ao interagir em comentários, fóruns e grupos de mensagens.', 'Quadro escolar, folhas com exemplos de mensagens amigáveis vs. hostis.', '50 minutos'),
(133, 5, 'Pegada Digital: A Memória da Internet', 'Debate sobre a permanência das postagens e como empresas e instituições examinam a reputação online de candidatos a bolsas de estudo, estágios e empregos.', 5, 'Compreender que as ações e publicações feitas online criam um rastro permanente que pode afetar o futuro pessoal e profissional.', 'Projetor ou TV, quadro escolar.', '50 minutos'),
(134, 5, 'Saúde Mental e o Tempo de Tela', 'Análise do fenômeno FOMO (medo de estar perdendo algo), insônia causada pela luz azul e ansiedade gerada pela busca de curtidas. Dicas para estabelecer momentos de desconexão.', 6, 'Refletir sobre a dependência gerada pelas notificações e aplicar estratégias para manter um uso equilibrado de aparelhos eletrônicos.', 'Ficha de autoavaliação impressa sobre uso de celular.', '50 minutos'),
(135, 5, 'Cidadania Ativa e Ativismo Digital Seguro', 'Estudo de como abaixo-assinados digitais, páginas comunitárias e aplicativos de ouvidoria pública ajudam a fiscalizar problemas urbanos e propor melhorias para o bairro.', 7, 'Identificar formas positivas de usar a internet para o benefício social, socialização de ideias e mobilização cidadã legítima.', 'Projetor ou TV, papel para planejar uma ação social escolar.', '50 minutos');
INSERT INTO aula (id, modulo_id, titulo, descricao, ordem, objetivo, recursos_necessarios, duracao_sugerida) VALUES
(136, 6, 'Introdução ao Projeto e Definição de Temas', 'O professor explica o projeto integrado. Os alunos se reúnem e decidem o problema de segurança, exclusão ou comportamento digital que gostariam de pesquisar localmente.', 1, 'Organizar grupos de trabalho e selecionar um problema digital ou de cidadania presente na comunidade dos estudantes.', 'Quadro escolar, folhas de papel e caneta para rascunhos.', '50 minutos'),
(137, 6, 'Elaboração de Pesquisa de Opinião Coletiva', 'Os grupos formulam perguntas objetivas para investigar como as pessoas ao redor percebem golpes de internet, notícias falsas ou se possuem dificuldades de acesso.', 2, 'Desenhar um questionário de pesquisa simples com poucas perguntas para ser aplicado com familiares ou vizinhos.', 'Folha de papel para redigir as perguntas estruturadas.', '50 minutos'),
(138, 6, 'Compilando as Respostas e Planejando o Conteúdo', 'Os alunos trazem os questionários respondidos, discutem os dados e escolhem o formato do seu produto informativo (pode ser uma cartilha, panfleto ou cartaz).', 3, 'Analisar as respostas coletadas na pesquisa de campo e rascunhar o material informativo de conscientização.', 'Cadernos, folhas extras para rascunho de layouts.', '50 minutos'),
(139, 6, 'Confecção Física da Campanha de Conscientização', 'Trabalho em grupo focado na criação artística e textual das soluções de orientação digital a serem divulgadas na escola ou comunidade.', 4, 'Produzir os cartazes ou livretos educativos baseando-se nos dados coletados.', 'Papel cartolina ou sulfite, canetas coloridas, lápis, réguas.', '50 minutos'),
(140, 6, 'Apresentação da Campanha e Discussão Geral', 'Apresentação curta de cada grupo para a turma, demonstrando o que descobriram e distribuindo ou expondo os cartazes na sala de aula ou nos corredores.', 5, 'Expor os resultados das investigações e debater as melhores formas de promover a cultura digital na escola.', 'Quadro escolar ou fitas adesivas para fixar os cartazes gerados pelos alunos.', '50 minutos');
INSERT INTO aula (id, modulo_id, titulo, descricao, ordem, objetivo, recursos_necessarios, duracao_sugerida) VALUES
(201, 7, 'A Estrutura do PC: A Placa-Mãe e as Conexões Físicas', 'Uma explicação visual sobre onde os componentes do computador se encaixam e como as trilhas e os fios (barramentos) transportam energia e dados elétricos de um lugar para o outro.', 1, 'Conhecer a placa-mãe como a central de interconexão física de todos os dispositivos do computador.', 'Projetor ou TV para fotos de alta resolução de placas-mãe, quadro escolar.', '50 minutos'),
(202, 7, 'A Força Bruta de Processamento: A CPU em Ação', 'Explicação de termos técnicos como "núcleos" (cores), velocidade em Gigahertz (GHz) e a importância do sistema de refrigeração (cooler) para manter o chip funcionando sem travar.', 2, 'Entender a função profunda do processador e os fatores que definem o seu rendimento básico.', 'Projetor ou TV, quadro.', '50 minutos'),
(203, 7, 'Velozes e Permanentes: RAM vs. SSD vs. HD', 'Análise prática de como a transição de HDs para SSDs mudou a velocidade de inicialização do sistema e de aplicativos, mostrando a hierarquia e taxas de velocidade de cada memória.', 3, 'Compreender a diferença de velocidade e funcionalidade entre os tipos de memórias no acesso diário de arquivos.', 'Amostras ou fotos de HDs mecânicos e SSDs, projetor ou TV.', '50 minutos'),
(204, 7, 'O Processador de Imagens: A GPU', 'Explicação de como a placa gráfica dedicada alivia o processador central (CPU) cuidando exclusivamente da parte visual pesada (jogos, edição de vídeo, modelagem e interfaces complexas).', 4, 'Compreender a diferença entre vídeo integrado e placa de vídeo dedicada (GPU) e sua relevância.', 'Projetor ou TV, quadro.', '50 minutos'),
(205, 7, 'O Equilíbrio da Fonte e da Energia no Sistema', 'Explicação sobre o papel da fonte de alimentação e como o mau funcionamento de um componente (gargalo de hardware) afeta todo o sistema, utilizando analogia de trânsito em estradas.', 5, 'Compreender a importância do fornecimento estável de energia elétrica e a coordenação de dados entre componentes.', 'Quadro escolar, projetor ou TV.', '50 minutos'),
(206, 7, 'Escolhendo o Computador Perfeito: Casos de Uso', 'Dinâmica de orçamento: em grupos, os alunos analisam catálogos fictícios para sugerir a melhor máquina para um estudante, um designer gráfico de baixo custo ou um escritório de vendas.', 6, 'Selecionar configurações de hardware ideais para perfis variados de usuários a partir de uma verba fictícia.', 'Tabelas de preços de hardware simuladas em papel, lápis e cadernos.', '50 minutos'),
(207, 7, 'Diagnósticos Básicos de Problemas de Hardware', 'Como detectar superaquecimento (cooler barulhento ou desliga sozinho), defeitos simples de memória RAM (apitos ao ligar), e problemas de cabo de energia ou conexões soltas.', 7, 'Identificar defeitos físicos comuns nos computadores a partir de comportamentos anômalos.', 'Quadro escolar, projetor ou TV.', '50 minutos');
INSERT INTO aula (id, modulo_id, titulo, descricao, ordem, objetivo, recursos_necessarios, duracao_sugerida) VALUES
(208, 8, 'O Maestro Virtual: Introdução ao Sistema Operacional', 'O papel do SO em organizar a memória, decidir qual programa roda primeiro e garantir que os componentes físicos funcionem de forma coordenada sem conflitos.', 1, 'Compreender o Sistema Operacional como o programa principal que traduz as ações do usuário em controle do hardware.', 'Projetor ou TV, quadro.', '50 minutos'),
(209, 8, 'Conhecendo as Interfaces: Windows vs. Linux', 'Apresentação das diferenças de filosofia e interfaces do Windows e do Linux. Discussão sobre a segurança, gratuidade e adaptabilidade do Linux em sistemas escolares.', 2, 'Diferenciar sistemas proprietários de sistemas de código aberto (software livre).', 'Capturas de tela das áreas de trabalho dos sistemas Windows e Linux projetadas.', '50 minutos'),
(210, 8, 'Sistemas de Bolso: Android e iOS', 'Discussão sobre como os sistemas móveis poupam energia e gerenciam aplicativos instalados em segundo plano, e como funcionam as lojas oficiais de aplicativos.', 3, 'Reconhecer a arquitetura e o funcionamento dos sistemas operacionais de celulares e tablets.', 'Projetor ou TV, quadro escolar.', '50 minutos'),
(211, 8, 'Instalação e Funcionamento dos Softwares', 'Explicação de onde ficam salvos os arquivos instalados no computador, a diferença de formatos executáveis (.exe, .deb, .apk) e os direitos de administrador ao baixar programas.', 4, 'Compreender o processo de instalação de programas e o conceito básico de arquivos executáveis.', 'Quadro escolar, projetor ou TV.', '50 minutos'),
(212, 8, 'Arquivando o Conhecimento: Organização de Arquivos e Pastas', 'Prática de organização de pastas no computador ou de forma simulada. Como usar a pesquisa integrada do sistema e a importância de manter nomenclaturas compreensíveis de arquivos.', 5, 'Estruturar diretórios e arquivos de forma lógica e identificar extensões comuns (.txt, .pdf, .docx, .png).', 'Projetor ou TV, folhas para atividade de estruturação em árvore.', '50 minutos'),
(213, 8, 'Manutenção Preventiva do Sistema: Limpeza e Atualização', 'Como apagar arquivos temporários, desinstalar programas inúteis que iniciam com o sistema e por que nunca ignorar as atualizações críticas de segurança do SO.', 6, 'Reconhecer a importância das atualizações de sistema para segurança e aplicar métodos de limpeza lógica de armazenamento.', 'Projetor ou TV, quadro.', '50 minutos'),
(214, 8, 'O Futuro da Computação Pessoal: Sistemas em Nuvem', 'O que são sistemas operacionais leves voltados para a web (como o ChromeOS) e a execução remota de programas pesados diretamente no navegador através de servidores virtuais.', 7, 'Compreender sistemas executados diretamente via navegadores e as tendências de virtualização.', 'Projetor ou TV, quadro escolar.', '50 minutos');
INSERT INTO aula (id, modulo_id, titulo, descricao, ordem, objetivo, recursos_necessarios, duracao_sugerida) VALUES
(215, 9, 'Desvendando a Lógica: Os Quatro Pilares', 'Introdução teórica sobre como o raciocínio computacional ajuda seres humanos a planejar soluções sistemáticas para problemas de qualquer área do conhecimento humano.', 1, 'Conhecer a definição e importância do Pensamento Computacional e seus quatro pilares estruturantes.', 'Projetor ou TV, quadro escolar.', '50 minutos'),
(216, 9, 'Dividir para Conquistar: Decomposição', 'Dinâmica em grupos: como organizar um evento escolar ou planejar a limpeza de uma casa quebrando o processo em dezenas de pequenas tarefas organizadas.', 2, 'Aplicar o pilar da decomposição para quebrar problemas grandes em partes menores e mais fáceis de resolver.', 'Fichas de tarefas impressas, quadro escolar.', '50 minutos'),
(217, 9, 'Enxergando Semelhanças: Reconhecimento de Padrões', 'Análise lúdica de sequências de eventos e fenômenos da natureza. A turma aprenderá como reaproveitar soluções de problemas anteriores para economizar tempo no presente.', 3, 'Identificar tendências, repetições e similaridades em dados e problemas do dia a dia.', 'Cartões de padrões coloridos, quadro escolar.', '50 minutos'),
(218, 9, 'Filtrando o Essencial: Abstração', 'Exercício utilizando mapas de metrô simplificados ou histórias com excesso de detalhes, onde os alunos devem extrair apenas o núcleo das informações úteis.', 4, 'Separar dados relevantes de detalhes desnecessários para focar na essência do problema.', 'Mapas ou textos detalhados em folhas impressas ou projetadas.', '50 minutos'),
(219, 9, 'Roteiros Rigorosos: Algoritmos no Dia a Dia', 'Exercício divertido de escrever o algoritmo exato para fazer um sanduíche de manteiga ou desenhar um quadrado, desafiando um colega a seguir as instruções ao pé da letra.', 5, 'Desenvolver sequências lógicas estruturadas passo a passo de forma clara, eliminando a ambiguidade.', 'Papel e caneta para escrita dos passos lógicos.', '50 minutos'),
(220, 9, 'Desenho de Decisões: Fluxogramas Simplificados', 'Como utilizar blocos de início, etapas de ação, blocos de decisão ("sim" ou "não") e fim de linha para esquematizar soluções simples de rotina diária no quadro.', 6, 'Representar graficamente algoritmos e fluxos de decisão por meio de formas geométricas básicas.', 'Quadro escolar, réguas de plástico ou cartões moldes de formas geométricas.', '50 minutos'),
(221, 9, 'Desafios de Lógica Desplugada', 'Uma competição cooperativa de resolução de problemas lógicos matemáticos e de dedução de forma desplugada, conectando os fundamentos estudados ao cotidiano escolar.', 7, 'Resolver enigmas aplicando conjuntamente os quatro pilares estudados de raciocínio computacional.', 'Folhas com enigmas de lógica impressos para os grupos.', '50 minutos');
INSERT INTO aula (id, modulo_id, titulo, descricao, ordem, objetivo, recursos_necessarios, duracao_sugerida) VALUES
(222, 10, 'Produção Textual nos Padrões Acadêmicos', 'Estruturação de um documento: margens, espaçamentos, títulos, sumários e como referenciar fontes bibliográficas de forma limpa em processadores de texto.', 1, 'Formatar relatórios e textos escolares seguindo diretrizes estruturais básicas de digitação (ABNT).', 'Projetor ou TV com editor de texto aberto para demonstração das ferramentas.', '50 minutos'),
(223, 10, 'As Bases das Planilhas Eletrônicas', 'Introdução ao uso de tabelas digitais. Os alunos aprenderão a inserir dados cadastrais e usar fórmulas de soma, subtração, multiplicação e média escolar.', 2, 'Compreender a estrutura de linhas, colunas, células e fórmulas aritméticas fundamentais.', 'Projetor ou TV demonstrando planilha aberta, quadro escolar.', '50 minutos'),
(224, 10, 'Gráficos e Organização Visual de Dados', 'Análise estatística de dados simples. A turma aprenderá a escolher o melhor tipo de gráfico para representar informações de comportamento de consumo ou notas escolares.', 3, 'Converter dados numéricos de tabelas em gráficos fáceis de interpretar (pizza, barras e linhas).', 'Projetor ou TV com planilha, quadro.', '50 minutos'),
(225, 10, 'Slides Incríveis: Design de Apresentações', 'Regras básicas de contraste de cores, tamanho de fontes legíveis, uso de tópicos pontuais, inserção de imagens explicativas e técnicas corporais básicas de apresentação de ideias.', 4, 'Projetar apresentações visuais harmônicas e equilibradas, fugindo do excesso de textos.', 'Exemplos de slides bons e ruins projetados.', '50 minutos'),
(226, 10, 'Trabalho Coletivo em Nuvem: Ferramentas Colaborativas', 'Como criar pastas compartilhadas, comentar em arquivos e trabalhar no mesmo texto ou apresentação ao mesmo tempo em tempo real com outras pessoas.', 5, 'Compartilhar e editar documentos de forma simultânea e assíncrona com colegas de grupo.', 'Computador ou celular de demonstração, projetor ou TV.', '50 minutos'),
(227, 10, 'Organização Pessoal: Calendários e Tarefas', 'Criação de lembretes, agendamento de trabalhos em grupo e prazos escolares usando agendas digitais, ensinando o estudante a planejar sua rotina de estudos de forma produtiva.', 6, 'Estruturar rotinas de estudos usando agendas virtuais e listas de tarefas compartilhadas.', 'Projetor ou TV, quadro escolar.', '50 minutos'),
(228, 10, 'Criando Meu Primeiro Portfólio Escolar', 'Metodologia de portfólio. Os alunos montarão uma estrutura contendo relatórios, fotos de projetos e slides organizados, preparando-os para o portfólio profissional futuro.', 7, 'Organizar produções acadêmicas do ano letivo em uma pasta digital organizada.', 'Quadro escolar, projetor ou TV.', '50 minutos');
INSERT INTO aula (id, modulo_id, titulo, descricao, ordem, objetivo, recursos_necessarios, duracao_sugerida) VALUES
(229, 11, 'Comunicação Visual e Editores Gráficos Gratuitos', 'Fundamentos de design de cartaz: posicionamento de elementos, paleta de cores harmoniosa, seleção de imagens de boa qualidade e escrita de chamadas textuais curtas e chamativas.', 1, 'Criar peças visuais básicas (cartazes e banners) utilizando ferramentas online e gratuitas de design.', 'Projetor ou TV, celulares dos alunos (se permitido) ou atividade com recortes.', '50 minutos'),
(230, 11, 'Capturando Ideias: Planejando um Vídeo', 'Planejamento de gravação. Como definir a introdução, desenvolvimento e conclusão em um roteiro de 2 minutos. Dicas de iluminação caseira usando a luz de janelas.', 2, 'Escrever um roteiro curto para gravação de vídeo explicativo e dominar enquadramentos básicos de câmera de celular.', 'Papel e caneta para escrita do roteiro.', '50 minutos'),
(231, 11, 'Edição Prática de Vídeos no Celular', 'Apresentação de ferramentas fáceis para celular. Como cortar erros de gravação, inserir trilhas sonoras livres de direitos autorais e exportar o vídeo para as redes sociais.', 3, 'Cortar, legendar e ajustar o som de vídeos gravados usando aplicativos gratuitos no smartphone.', 'Celular com app de edição instalado (opcional, para visualização de menus), projetor ou TV.', '50 minutos'),
(232, 11, 'Podcasts: Planejamento e Roteiro de Áudio', 'O que torna um áudio atraente. Como prender a atenção do ouvinte usando vinhetas, tom de voz adequado e estrutura de perguntas e respostas em podcasts de entrevistas.', 4, 'Compreender o formato de podcast e estruturar um roteiro dinâmico de conversação.', 'Exemplos curtos de áudios de podcasts famosos de educação ou cultura, quadro.', '50 minutos'),
(233, 11, 'Captando e Editando Áudio Digital', 'Prática de tratamento de som. Uso de editores de áudio fáceis para celulares e notebooks. Ajustes de volume de voz em relação à trilha sonora de fundo.', 5, 'Gravar e ajustar áudio, eliminando ruídos básicos de fundo e mesclando com música.', 'Projetor ou TV com tela de editor de som, quadro.', '50 minutos'),
(234, 11, 'Direitos de Imagem e Licenciamento das Produções', 'Como liberar produções autorais para uso público gratuito sem perder a autoria. Cuidados ao utilizar rostos de pessoas reais e vozes sem autorização expressa em vídeos escolares.', 6, 'Registrar e publicar produções autorais utilizando licenças Creative Commons, e respeitar imagens alheias.', 'Quadro escolar, panfleto ilustrativo de tipos de licenças Creative Commons.', '50 minutos'),
(235, 11, 'Curadoria Ética de Conteúdos Digitais', 'A importância de não ser apenas um "copiador de links". Como montar uma curadoria interessante e contextualizada de vídeos e leituras úteis sobre um assunto para outras pessoas.', 7, 'Filtrar, classificar e partilhar informações da internet com comentários explicativos de forma ética.', 'Quadro escolar, projetor ou TV.', '50 minutos');
INSERT INTO aula (id, modulo_id, titulo, descricao, ordem, objetivo, recursos_necessarios, duracao_sugerida) VALUES
(236, 12, 'Proposição de Desafios da Rotina Escolar', 'Debate coletivo sobre gargalos na escola (organização da fila do refeitório, devolução de livros da biblioteca, horários de salas de estudos) para escolher o tema do projeto.', 1, 'Mapear problemas do dia a dia da escola que possam ser otimizados através de processos lógicos ou ferramentas digitais simples.', 'Quadro escolar, cadernos para anotações das sugestões.', '50 minutos'),
(237, 12, 'Modelagem Conceitual da Solução Escolhida', 'Rascunho da solução no papel. Os alunos desenharão os fluxos lógicos e decisões que fariam o problema mapeado na aula anterior sumir ou diminuir drasticamente.', 2, 'Aplicar a decomposição e os algoritmos para planejar passo a passo o funcionamento do processo a ser melhorado.', 'Papel quadriculado ou pautado, réguas, lápis e borracha.', '50 minutos'),
(238, 12, 'Prototipação em Papel das Interfaces (Wireframes)', 'Desenvolvimento prático das telas. Como o usuário veria as informações? Rascunhos de botões, formulários e textos explicativos utilizando cartões de cartolina ou papel sulfite.', 3, 'Desenhar de forma desplugada as telas de um aplicativo fictício ou os cartazes de fluxo para os usuários.', 'Papel sulfite, lápis, canetas, tesouras e réguas.', '50 minutos'),
(239, 12, 'Preparação dos Elementos de Apresentação e Dados', 'Tabulação simples. Os alunos criarão projeções do tempo economizado ou custos reduzidos para a escola caso a solução planejada por eles fosse implementada de verdade.', 4, 'Estruturar tabelas ou gráficos estimativos de benefícios da solução e preparar cartazes informativos do projeto.', 'Cadernos, calculadoras simples ou folhas de papel pautado.', '50 minutos'),
(240, 12, 'O Pitch do Projeto: Apresentação para a Turma', 'Os grupos apresentam suas soluções para a turma do mesmo modo que startups fazem. A sala debate a viabilidade de cada sugestão e como elas melhoram o ambiente escolar.', 5, 'Comunicar de forma sucinta (pitch de 3 minutos) a ideia do projeto e recolher avaliações críticas dos colegas.', 'Cronômetro de contagem do tempo de apresentação, quadro escolar.', '50 minutos');
INSERT INTO aula (id, modulo_id, titulo, descricao, ordem, objetivo, recursos_necessarios, duracao_sugerida) VALUES
(301, 13, 'O Despertar da IA: Histórico e Conceito Básico', 'Apresentação da IA, diferenciando robôs de filmes de ficção científica de sistemas lógicos reais baseados em algoritmos matemáticos complexos. Apresentação do clássico teste de Turing.', 1, 'Compreender o que define a Inteligência Artificial e conhecer momentos marcantes do seu surgimento científico.', 'Projetor ou TV, quadro escolar.', '50 minutos'),
(302, 13, 'Como os Sistemas Aprendem: Machine Learning', 'Apresentação de como computadores analisam padrões e tomam decisões sem serem programados especificamente para isso, mostrando a importância dos dados de treino e verificação de erros.', 2, 'Explicar conceitualmente como funciona o aprendizado de máquina com base em dados históricos.', 'Projetor ou TV, quadro escolar.', '50 minutos'),
(303, 13, 'A Era da IA Generativa e Grandes Modelos de Linguagem', 'Como as novas IAs conseguem criar redações ou imagens realistas. Os alunos aprenderão a dialogar com as IAs de forma rica e específica usando instruções detalhadas (prompts estruturados).', 3, 'Reconhecer o funcionamento básico de modelos geradores de textos e imagens e aprender a redigir instruções eficazes (prompts).', 'Celulares dos alunos (se permitido) ou projetor exibindo interações reais de IA.', '50 minutos'),
(304, 13, 'IA no Nosso Dia a Dia: A Recomendação Invisível', 'Como os feeds de redes sociais nos conhecem tão bem. Discussão sobre a captura de cliques, curtidas e tempo gasto em fotos que retroalimentam as escolhas das IAs.', 4, 'Identificar a atuação cotidiana da IA em redes sociais, streamings, assistentes de voz e rotas de trânsito.', 'Projetor ou TV, quadro.', '50 minutos'),
(305, 13, 'Os Limites da Máquina: Consciência vs. Processamento', 'Por que as IAs às vezes inventam dados e não possuem consciência, empatia ou sentimentos. A importância de manter o olhar crítico e a supervisão humana sobre as respostas de sistemas autônomos.', 5, 'Perceber as limitações das ferramentas de inteligência artificial, como a falta de inteligência emocional e a ocorrência de respostas erradas (alucinações).', 'Exemplos de erros famosos cometidos por IAs impressos ou projetados.', '50 minutos'),
(306, 13, 'Ética na IA: Vieses de Dados e Preconceitos Algorítmicos', 'Debate sobre erros em sistemas automatizados de seleção de candidatos, reconhecimento facial e segurança pública, demonstrando que a IA herda preconceitos dos humanos que a treinaram.', 6, 'Analisar criticamente as injustiças sociais causadas por inteligências artificiais com dados enviesados históricos.', 'Notícias impressas sobre vieses algorítmicos e discriminação tecnológica.', '50 minutos'),
(307, 13, 'A IA e o Trabalho: Preparando-se para o Futuro', 'Análise do mercado futuro. Os alunos discutirão quais tarefas operacionais tendem a sumir e a relevância de aprender a colaborar com sistemas de IA para se destacar no ambiente de trabalho.', 7, 'Refletir sobre as profissões que passarão por transformações radicais por conta da automação e identificar novas oportunidades.', 'Projetor ou TV, quadro escolar.', '50 minutos');
INSERT INTO aula (id, modulo_id, titulo, descricao, ordem, objetivo, recursos_necessarios, duracao_sugerida) VALUES
(308, 14, 'A Jornada do Software: Do Planejamento ao Lançamento', 'Uma explicação voltada à gestão de projetos. Os estudantes entenderão que programar é apenas uma das etapas da criação de um produto digital útil e funcional.', 1, 'Conhecer o ciclo de vida do desenvolvimento de um programa (análise de problemas, design, programação, testes e sustentação).', 'Projetor ou TV, quadro.', '50 minutos'),
(309, 14, 'O Esqueleto da Web: HTML, CSS e JavaScript', 'Analogia da casa: o HTML é a estrutura e as paredes de tijolo; o CSS é a cor da tinta, acabamento e estilo; o JavaScript é o sistema elétrico e hidráulico que traz dinamismo e movimento.', 2, 'Entender conceitualmente a função de cada linguagem na composição visual e funcional de um site.', 'Quadro escolar, cartões ilustrando tags e estilos de design simples.', '50 minutos'),
(310, 14, 'Como Funcionam os Apps nos Celulares?', 'O caminho dos aplicativos: como o celular (cliente) envia dados e solicita informações para computadores remotos (servidores) para carregar telas e dados atualizados em tempo real.', 3, 'Compreender a lógica de comunicação cliente-servidor e a publicação de aplicativos nas lojas virtuais.', 'Projetor ou TV, quadro escolar.', '50 minutos'),
(311, 14, 'O que Existe Atrás da Tela? Interfaces, Lógicas e Bancos de Dados', 'Apresentação dos conceitos de front-end (o que o usuário vê e toca) e back-end (o que roda nos servidores, controlando regras de negócio e guardando dados).', 4, 'Identificar a conexão entre a interface visual do usuário, a lógica de programação do servidor e o armazenamento do banco de dados.', 'Quadro escolar, projetor ou TV.', '50 minutos'),
(312, 14, 'O Time de Tecnologia: Papéis e Funções', 'Apresentação de carreiras como Designer UX/UI (foco no usuário), Gerente de Produto (PM), Programador Front-end/Back-end, Testador (QA) e Administrador de Banco de Dados.', 5, 'Conhecer a atuação de diferentes especialistas que cooperam para construir soluções digitais.', 'Projetor ou TV, quadro.', '50 minutos'),
(313, 14, 'Organização com Metodologias Ágeis', 'O que é metodologia ágil. Os alunos farão uma dinâmica prática de Kanban na lousa usando notas autoadesivas divididas em colunas de "A Fazer", "Fazendo" e "Concluído" para organizar um trabalho coletivo.', 6, 'Aplicar conceitos de organização de tarefas compartilhadas em quadros virtuais ou físicos (Kanban).', 'Notas autoadesivas (post-its) ou fitas crepe, quadro escolar.', '50 minutos'),
(314, 14, 'Plataformas Sem Código (No-Code)', 'Apresentação de construtores visuais de páginas e blogs. Discussão sobre como essas ferramentas facilitam o empreendedorismo social de forma simples, rápida e barata.', 7, 'Conhecer o potencial das tecnologias sem código para a validação rápida de projetos de sites e portfólios pessoais.', 'Projetor ou TV demonstrando ferramentas visuais online de criação de páginas.', '50 minutos');
INSERT INTO aula (id, modulo_id, titulo, descricao, ordem, objetivo, recursos_necessarios, duracao_sugerida) VALUES
(315, 15, 'Dados Pessoais: O Novo Ouro Digital', 'Por que redes sociais e serviços são oferecidos de graça? Os alunos entenderão que seus dados pessoais e perfis de hábitos de consumo são a mercadoria que financia o mundo digital de anúncios direcionados.', 1, 'Reconhecer o valor estratégico e financeiro dos dados pessoais na economia contemporânea de dados.', 'Projetor ou TV, quadro escolar.', '50 minutos'),
(316, 15, 'Direitos do Cidadão na Rede: A LGPD', 'Estudo prático da lei de dados brasileira. O que são dados sensíveis? Como pedir a exclusão de cadastros na rede e por que sites pedem consentimento para uso de "cookies".', 2, 'Conhecer as bases da Lei Geral de Proteção de Dados (LGPD) e saber quais são os direitos garantidos aos cidadãos sobre suas informações.', 'Texto impresso ou projetado com trechos simplificados e explicados da LGPD.', '50 minutos'),
(317, 15, 'Hackeando Mentes: A Engenharia Social', 'O perigo de falar com estranhos. Análise de táticas como urgência falsa, autoridade simulada e apelo emocional usadas para fazer as pessoas fornecerem senhas ou códigos voluntariamente.', 3, 'Identificar táticas de indução psicológica usadas por golpistas para roubar dados por ligações telefônicas ou mensagens eletrônicas.', 'Casos de áudios ou relatos de engenharia social transcritos ou gravados.', '50 minutos'),
(318, 15, 'Vírus, Cavalos de Troia e Ransomware: Malwares', 'Apresentação sobre vírus que se copiam, cavalos de troia que fingem ser programas úteis e o temido ransomware (que sequestra e cobra resgate por arquivos das vítimas).', 4, 'Classificar as diferentes categorias de programas maliciosos que danificam ou bloqueiam arquivos em computadores.', 'Projetor ou TV, quadro.', '50 minutos'),
(319, 15, 'Criptografia e Cadeado de Segurança', 'Uma explicação simplificada e visual sobre como chaves públicas e privadas misturam as mensagens para que estranhos no caminho do Wi-Fi não consigam ler dados de conversas ou transações bancárias.', 5, 'Entender conceitualmente como a criptografia protege transações digitais e tráfego de dados confidenciais.', 'Quadro escolar, envelopes de papel e chaves físicas de demonstração.', '50 minutos'),
(320, 15, 'Proteção Vital: Rotinas de Backup Seguro', 'Regras práticas de backup (regra 3-2-1: três cópias, duas mídias físicas diferentes, uma na nuvem). Vantagens e perigos das sincronizações automáticas em computadores e celulares.', 6, 'Aplicar planos eficientes de cópias de segurança para evitar perda acidental de relatórios escolares ou dados pessoais.', 'Quadro escolar, dispositivos de armazenamento como pendrive ou HD externo (opcional).', '50 minutos'),
(321, 15, 'Criando um Plano de Emergência Digital', 'Passo a passo prático para recuperar contas: como notificar contatos da invasão do WhatsApp, boletim de ocorrência online, acionamento do banco em fraudes de PIX e contato com provedores de e-mail.', 7, 'Construir um roteiro de ações a serem executadas em casos de invasão de contas ou clonagem de aplicativos.', 'Ficha de preenchimento estruturada do plano de contingência, quadro.', '50 minutos');
INSERT INTO aula (id, modulo_id, titulo, descricao, ordem, objetivo, recursos_necessarios, duracao_sugerida) VALUES
(322, 16, 'Pontes e Abismos: A Inclusão Digital no Brasil', 'Reflexão sobre as dificuldades enfrentadas por pessoas sem acesso a serviços online de saúde, matrículas e bancos. O estudante debaterá soluções coletivas locais de inclusão digital.', 1, 'Debater o impacto social gerado pela ausência de computadores e internet de qualidade nas comunidades de baixa renda.', 'Gráficos estatísticos de conectividade por regiões brasileiras.', '50 minutos'),
(323, 16, 'O Rastro Energético: Sustentabilidade e Pegada de Carbono Digital', 'Os dados possuem peso ecológico. A energia gasta por grandes centros de dados que rodam IAs e mantêm streaming ligados. Dicas como apagar e-mails velhos e reduzir resoluções de vídeos quando desnecessários.', 2, 'Reconhecer a demanda energética exigida pelo tráfego de dados de internet e servidores e propor atitudes sustentáveis digitais.', 'Infográficos ambientais, projetor ou TV, quadro.', '50 minutos'),
(324, 16, 'O Lixo do Futuro: Descarte e Reciclagem Eletrônica', 'Componentes tóxicos (chumbo, mercúrio) contidos nas placas de computadores. Como funcionam cooperativas de reciclagem especializada e postos de coleta locais na própria cidade.', 3, 'Analisar a contaminação ambiental provocada pelo descarte inadequado de pilhas, baterias, celulares e computadores.', 'Notícias ou mapas de pontos de reciclagem locais.', '50 minutos'),
(325, 16, 'Dependência Tecnológica e Saúde Psicológica', 'Discussão aberta sobre ansiedade provocada pelas redes sociais e padrões estéticos inalcançáveis de influenciadores digitais, criando estratégias saudáveis para desligar aparelhos à noite.', 4, 'Avaliar o impacto das notificações constantes, jogos viciantes e do isolamento gerado por telas na vida emocional de adolescentes.', 'Quadro escolar, folhas para relatos anônimos sobre experiências emocionais com redes.', '50 minutos'),
(326, 16, 'Deepfakes e Desinformação Visual Avançada', 'O avanço das deepfakes (vídeos manipulados ultrarrealistas). Como essa técnica é usada de forma criminosa e como os alunos podem detectar indícios de simulação por inteligência artificial em fotos e áudios.', 5, 'Reconhecer manipulações visuais e sonoras complexas criadas por IAs e os riscos decorrentes para a democracia e imagem de pessoas comuns.', 'Exemplos de imagens/vídeos simulados projetados ou impressos para análise.', '50 minutos'),
(327, 16, 'O Viés da Automação: Quem Decide o Nosso Futuro?', 'Discussão sobre algoritmos que decidem empréstimos, tratamentos de saúde ou sentenças judiciais automáticas. A importância de reter a auditoria humana e de processos abertos na tecnologia.', 6, 'Refletir sobre a delegação de julgamentos humanos críticos a softwares e sistemas inteligentes de inteligência artificial.', 'Estudo de caso impresso sobre erro de automação médica ou financeira para debate.', '50 minutos'),
(328, 16, 'Leis Digitais e a Governança das Redes', 'O Marco Civil da Internet no Brasil, a Lei Carolina Dieckmann de invasão de dispositivos e a discussão global sobre como regulamentar fake news e os limites das redes sociais de forma deocrática.', 7, 'Conhecer leis importantes brasileiras sobre crimes cibernéticos e debates sobre governança tecnológica.', 'Projetor ou TV, quadro.', '50 minutos');
INSERT INTO aula (id, modulo_id, titulo, descricao, ordem, objetivo, recursos_necessarios, duracao_sugerida) VALUES
(329, 17, 'Carreiras do Código: Ciência da Computação vs. Engenharia de Software', 'Apresentação das matrizes curriculares de forma simples. A ciência da computação (foco em pesquisa científica, algoritmos complexos e lógica) contra a engenharia de software (foco em processos de criação de programas, arquitetura, testes e liderança).', 1, 'Compreender as diferenças de formação acadêmica, campos de estudo e atividades profissionais entre essas duas graduações.', 'Projetor ou TV, quadro escolar.', '50 minutos'),
(330, 17, 'Gestão e Dados: Sistemas de Informação', 'O que faz quem trabalha nessa área? Foco em planejamento de soluções digitais corporativas, automação comercial, análise de requisitos de clientes e coordenação tecnológica de negócios.', 2, 'Identificar a atuação do profissional de Sistemas de Informação como ponte entre tecnologia e administração.', 'Quadro escolar, projetor ou TV.', '50 minutos'),
(331, 17, 'Empatia Visual: Design Digital e Experiência do Usuário (UX/UI)', 'Entendendo o UX (experiência do usuário) e UI (interface do usuário). Como esses profissionais estudam o comportamento humano para decidir cores de botões, posições de ícones e garantir a acessibilidade de pessoas com deficiência.', 3, 'Conhecer o trabalho dos designers na facilitação de interfaces digitais amigáveis, bonitas e acessíveis.', 'Exemplos de layouts de páginas mobile bem e mal elaboradas projetados.', '50 minutos'),
(332, 17, 'Guardiões Digitais: Infraestrutura de Redes e Cibersegurança', 'O papel crítico de manter a internet e os sistemas corporativos no ar, prevenindo contra invasões externas e gerenciando servidores físicos e virtuais de tráfego de dados.', 4, 'Conhecer o dia a dia e responsabilidades dos administradores de redes de computadores e especialistas em segurança de sistemas.', 'Projetor ou TV, quadro escolar.', '50 minutos'),
(333, 17, 'Analisando o Futuro: Engenheiros e Cientistas de Dados', 'A profissão de analista e cientista de dados. Como estatísticas unidas a tecnologias digitais geram previsões úteis de vendas, surtos de doenças urbanas e hábitos populacionais.', 5, 'Compreender a importância de capturar, limpar e interpretar padrões em grandes volumes de dados para tomar decisões comerciais e científicas.', 'Projetor ou TV, quadro.', '50 minutos'),
(334, 17, 'Desbravando IAs: Profissionais do Treinamento de Máquinas', 'O que faz quem trabalha ensinando sistemas inteligentes ou testando o limite de algoritmos generativos. A importância de dominar habilidades multidisciplinares (matemática, linguística, ética) nessa carreira.', 6, 'Identificar carreiras recentes de engenharia de IA, especialistas em prompts e desenvolvedores de robótica inteligente.', 'Quadro escolar, projetor ou TV.', '50 minutos'),
(335, 17, 'Educação Continuada e Criação de Portfólio na Área Tecnológica', 'Como o profissional de tecnologia estuda constantemente de forma autônoma para não ficar obsoleto. O valor de portfólios autorais públicos para atrair recrutadores de emprego e processos seletivos.', 7, 'Planejar passos de desenvolvimento profissional, conhecendo cursos livres, certificações técnicas e formas de divulgar conhecimentos.', 'Exemplos simples de perfis profissionais de apresentação ou sites portfólio projetados.', '50 minutos');
INSERT INTO aula (id, modulo_id, titulo, descricao, ordem, objetivo, recursos_necessarios, duracao_sugerida) VALUES
(336, 18, 'Concepção de Projetos Sociais Tecnológicos', 'Formação dos times de trabalho no terceiro ano. Os estudantes decidem sobre qual questão local (como auxílio para idosos usarem celulares, doações de lixo eletrônico ou combate a golpes virtuais locais) irão desenvolver a ideia de projeto de impacto social.', 1, 'Escolher um problema ético, ecológico ou de inclusão digital da comunidade local para propor uma solução de utilidade pública.', 'Quadro escolar, folhas de papel e canetas.', '50 minutos'),
(337, 18, 'Arquitetura Geral da Solução Proposta', 'Os times estruturarão no papel: onde os dados da solução entram? Como seriam processados? Haverá banco de dados? Algum módulo usaria IA? Desenho de fluxogramas funcionais completos e integrados.', 2, 'Esquematizar de forma detalhada o fluxo de funcionamento e componentes da aplicação idealizada pelos alunos.', 'Papel cartolina, réguas, marcadores coloridos.', '50 minutos'),
(338, 18, 'Análise de Viabilidade Ética, Legal (LGPD) e Ambiental', 'Debate ético do projeto: como a solução gerencia os dados de usuários de forma legal? Ela exclui dados quando solicitado? Como a tecnologia atende pessoas com deficiência auditiva ou visual?', 3, 'Analisar a conformidade legal do projeto com a LGPD e estimar impactos de privacidade e acessibilidade na comunidade.', 'Quadro escolar, checklist de diretrizes éticas em folha.', '50 minutos'),
(339, 18, 'Criação de Protótipo de Apresentação das Telas', 'Trabalho prático de desenho de telas (protótipo funcional em papel ou com slides simples vinculados por links clicáveis), preparando-os para demonstrar o visual completo de seu projeto a terceiros.', 4, 'Produzir interfaces ilustrativas da solução desenhadas no papel ou através de softwares de design simples.', 'Papel cartolina ou sulfite, canetas hidrográficas coloridas, tesouras.', '50 minutos'),
(340, 18, 'Feira Tecnológica EduComp: Exposição Final de Protótipos', 'Exposição e compartilhamento geral. Cada grupo expõe seu cartaz e simula o fluxo do seu protótipo de software ou serviço para o resto da escola e colegas, recebendo feedbacks de utilidade social.', 5, 'Apresentar os protótipos de impacto social em formato de feira escolar e debater os aprendizados curriculares do curso.', 'Espaço físico escolar com mesas, fita adesiva para fixar materiais.', '50 minutos');
